CREATE PROCEDURE [Reporting].[SlicerDicer_DM_Access_PBI]
AS
BEGIN
SET NOCOUNT ON;

WITH ADDITIONAL
AS (
    SELECT clarity.dbo.CLARITY_EMP.[USER_ID]
        ,USER_TYPE_C
    FROM clarity.dbo.CLARITY_EMP
    LEFT JOIN clarity.dbo.USER_TYPE
        ON clarity.dbo.CLARITY_EMP.[USER_ID] = clarity.dbo.USER_TYPE.[USER_ID]
    LEFT JOIN clarity.dbo.CLARITY_EMP_2 ON clarity.dbo.CLARITY_EMP_2.[USER_ID] = clarity.dbo.USER_TYPE.[USER_ID]
    LEFT JOIN clarity.dbo.BI_SEC_POINTS
        ON clarity.dbo.CLARITY_EMP_2.ANALYTICS_ECL_ID = clarity.dbo.BI_SEC_POINTS.ECL_ID
    WHERE clarity.dbo.CLARITY_EMP.EMP_RECORD_TYPE_C = 1
        AND clarity.dbo.BI_SEC_POINTS.BI_SEC_POINTS_C IN (3, 9)
)
,SYSTEM_ASSGNMNT
AS (
    SELECT clarity.dbo.CLARITY_EMP.[USER_ID]
        ,CACHED_USER_TYPE_C
    FROM clarity.dbo.CLARITY_EMP
    LEFT JOIN clarity.dbo.CACHED_USER_TYPE
        ON clarity.dbo.CLARITY_EMP.[USER_ID] = clarity.dbo.CACHED_USER_TYPE.[USER_ID]
    LEFT JOIN clarity.dbo.CLARITY_EMP_2 ON clarity.dbo.CLARITY_EMP_2.[USER_ID] = clarity.dbo.CLARITY_EMP.[USER_ID]
    LEFT JOIN clarity.dbo.BI_SEC_POINTS
        ON clarity.dbo.CLARITY_EMP_2.ANALYTICS_ECL_ID = clarity.dbo.BI_SEC_POINTS.ECL_ID
    WHERE clarity.dbo.CLARITY_EMP.EMP_RECORD_TYPE_C = 1
        AND clarity.dbo.BI_SEC_POINTS.BI_SEC_POINTS_C IN (3, 9)
)
,PREFERRED
AS (
    SELECT ISNULL(COMPILED.COMPILED_RECORD_ID, BASE.DATA_MODEL_ID) AS "PREFERRED_ID"
    FROM clarity.dbo.DATA_MODEL_DEFINITIONS AS BASE
    LEFT JOIN (
        SELECT BASE_RECORD_ID, DATA_MODEL_ID AS COMPILED_RECORD_ID
        FROM clarity.dbo.DATA_MODEL_DEFINITIONS
        WHERE RECORD_STATUS_C = '4' AND OVERRIDE_CONTEXT_C = '1' AND OVERRIDE_REC_STAT_C = '2'
    ) AS COMPILED ON BASE.DATA_MODEL_ID = COMPILED.BASE_RECORD_ID
)
,USERS
AS (
    SELECT clarity.dbo.CLARITY_EMP.[USER_ID] as MASTER_USER_ID
        ,clarity.dbo.BI_SEC_POINTS.BI_SEC_POINTS_C
    FROM clarity.dbo.CLARITY_EMP
    LEFT JOIN clarity.dbo.CLARITY_EMP_2
        ON clarity.dbo.CLARITY_EMP.[USER_ID] = clarity.dbo.CLARITY_EMP_2.[USER_ID]
    LEFT JOIN clarity.dbo.BI_SEC_POINTS
        ON clarity.dbo.CLARITY_EMP_2.ANALYTICS_ECL_ID = clarity.dbo.BI_SEC_POINTS.ECL_ID
)
,MODEL_LIST
AS (
    SELECT PREFERRED_ID DATA_MODEL_ID FROM PREFERRED
)
,MASTER_USERS
AS (
    SELECT *
    FROM USERS CROSS JOIN MODEL_LIST
    WHERE USERS.BI_SEC_POINTS_C IN (3)
)

SELECT DISTINCT clarity.dbo.DATA_MODEL_DEFINITIONS.DATA_MODEL_ID as [Data Model ID]
    ,clarity.dbo.DATA_MODEL_DEFINITIONS.RECORD_NAME as [Data Model Name]
    ,SYSTEM_ASSGNMNT.[USER_ID] as [User ID]
    ,clarity.dbo.CLARITY_EMP.NAME as [User Name]
    ,clarity.dbo.ZC_USER_TYPES.NAME as [User Type/Report Group]
    ,'No' AS [Master Access?]
FROM SYSTEM_ASSGNMNT
LEFT JOIN ADDITIONAL ON ADDITIONAL.[USER_ID] = SYSTEM_ASSGNMNT.[USER_ID]
    AND ADDITIONAL.USER_TYPE_C = SYSTEM_ASSGNMNT.CACHED_USER_TYPE_C
LEFT JOIN clarity.dbo.CLARITY_EMP ON SYSTEM_ASSGNMNT.[USER_ID] = clarity.dbo.CLARITY_EMP.[USER_ID]
LEFT JOIN clarity.dbo.CLARITY_EMP_2 EMP2 ON EMP2.[USER_ID] = SYSTEM_ASSGNMNT.[USER_ID]
LEFT JOIN clarity.dbo.CLARITY_ECL ON clarity.dbo.CLARITY_ECL.ECL_ID = EMP2.ANALYTICS_ECL_ID
LEFT JOIN clarity.dbo.ZC_USER_TYPES ON SYSTEM_ASSGNMNT.CACHED_USER_TYPE_C = clarity.dbo.ZC_USER_TYPES.USER_TYPES_C
LEFT JOIN clarity.dbo.DATA_MODEL_USER_TYPE_SPEC ON clarity.dbo.DATA_MODEL_USER_TYPE_SPEC.USER_TYPES_C = SYSTEM_ASSGNMNT.CACHED_USER_TYPE_C
LEFT JOIN PREFERRED ON PREFERRED.PREFERRED_ID = clarity.dbo.DATA_MODEL_USER_TYPE_SPEC.DATA_MODEL_ID
LEFT JOIN clarity.dbo.DATA_MODEL_DEFINITIONS ON clarity.dbo.DATA_MODEL_DEFINITIONS.DATA_MODEL_ID = PREFERRED.Preferred_ID
WHERE SYSTEM_ASSGNMNT.CACHED_USER_TYPE_C IS NOT NULL
    AND (clarity.dbo.DATA_MODEL_DEFINITIONS.INACTIVE_YN IS NULL OR clarity.dbo.DATA_MODEL_DEFINITIONS.INACTIVE_YN = 'N')
    AND clarity.dbo.DATA_MODEL_DEFINITIONS.DATA_MODEL_ID IS NOT NULL

UNION ALL

SELECT DISTINCT clarity.dbo.DATA_MODEL_DEFINITIONS.DATA_MODEL_ID as [Data Model ID]
    ,clarity.dbo.DATA_MODEL_DEFINITIONS.RECORD_NAME as [Data Model Name]
    ,clarity.dbo.CLARITY_EMP.[USER_ID] as [User ID]
    ,clarity.dbo.CLARITY_EMP.NAME as [User Name]
    ,clarity.dbo.ZC_ALLOWABLE_GRPS.Name as [User Type/Report Group]
    ,'No' AS [Master Access?]
FROM clarity.dbo.CLARITY_EMP
LEFT JOIN clarity.dbo.CLARITY_EMP_2 EMP2 ON EMP2.[USER_ID] = clarity.dbo.CLARITY_EMP.[USER_ID]
LEFT JOIN clarity.dbo.BI_SEC_POINTS ON EMP2.ANALYTICS_ECL_ID = clarity.dbo.BI_SEC_POINTS.ECL_ID
LEFT JOIN clarity.dbo.CLARITY_ECL ON clarity.dbo.CLARITY_ECL.ECL_ID = EMP2.ANALYTICS_ECL_ID
LEFT JOIN clarity.dbo.RW_SEC_RPTGRPS_BASE ON clarity.dbo.RW_SEC_RPTGRPS_BASE.[USER_ID] = clarity.dbo.CLARITY_EMP.[USER_ID]
LEFT JOIN clarity.dbo.ZC_ALLOWABLE_GRPS ON clarity.dbo.ZC_ALLOWABLE_GRPS.ALLOWABLE_GRPS_C = clarity.dbo.RW_SEC_RPTGRPS_BASE.CLTY_RPT_GRP_C
LEFT JOIN clarity.dbo.DATA_MODEL_REPORT_GROUPS ON clarity.dbo.DATA_MODEL_REPORT_GROUPS.REPORT_GROUPS_C = clarity.dbo.ZC_ALLOWABLE_GRPS.ALLOWABLE_GRPS_C
LEFT JOIN PREFERRED ON PREFERRED.PREFERRED_ID = clarity.dbo.DATA_MODEL_REPORT_GROUPS.DATA_MODEL_ID
LEFT JOIN clarity.dbo.DATA_MODEL_DEFINITIONS ON clarity.dbo.DATA_MODEL_DEFINITIONS.DATA_MODEL_ID = PREFERRED.Preferred_ID
WHERE clarity.dbo.ZC_ALLOWABLE_GRPS.ALLOWABLE_GRPS_C IS NOT NULL
    AND clarity.dbo.BI_SEC_POINTS.BI_SEC_POINTS_C IN (3, 9)
    AND clarity.dbo.DATA_MODEL_DEFINITIONS.DATA_MODEL_ID IS NOT NULL

ORDER BY [Data Model Name], [User Name]
END
